  assert(Number(phase309.maxModeL2NormDeviationFromUnity ?? 1) < 1e-9, "Phase309 source modes must remain unit normalized.");
  assert(phase309.sourceModesAreUnitNormCoordinateVectors === true, "Phase309 must classify source modes as unit-norm coordinate vectors.");
  assert(phase309.sqrtVectorLengthScaleIsNormConversion === true, "Phase309 must identify sqrt(vector length) as the norm conversion candidate.");
  assert(phase309.vectorLengthScaleIsCoordinateCount === true, "Phase309 must classify vector length as coordinate count.");
  assert(phase309.vectorLengthScaleIsNotL2MeasureConversion === true, "Phase309 must reject vector length as an L2 measure conversion.");
  assert(phase309.hiddenMeasureConversionPresent === false, "Phase309 cannot claim a hidden vector-length measure conversion.");
  assert(phase309.sourceModeVectorLengthApplicationTheoremPresent === false, "Phase309 cannot claim a source-mode-vector-length application theorem.");
  assert(phase309.sourceModeVectorLengthScalePromotable === false, "Phase309 cannot promote the source-mode-vector-length scale.");
  assert(phase309.phase302VectorLengthCasimirLeadRecorded === true, "Phase309 must inherit the Phase302 vector-length/Casimir lead.");
  assert(phase309.phase308ScaleTransferStillBlocked === true, "Phase309 must inherit Phase308 scale-transfer blockage.");
  assert(phase309.phase308ScaleTransferAllowed === false, "Phase309 must preserve Phase308 transfer disallowance.");
  assert(phase309.phase308CanFillPhase201WzContract === false, "Phase309 must preserve Phase308 non-fill of the W/Z contract.");
  assert(phase309.canFillPhase201WzContract === false, "Phase309 cannot fill the Phase201 W/Z contract.");
  assert(phase309.wzMissingFieldCount === missingWzFields, "Phase309 W/Z missing-field count must match Phase213.");
  assert(phase309.higgsMissingFieldCount === missingHiggsFields, "Phase309 Higgs missing-field count must match Phase213.");
  assert(phase310.completionVariationalBranchToWzNormalizationAuditPassed === true, "Phase310 completion variational branch audit must pass as a non-promotional audit.");
  assert(phase310.targetObservablesUsedForConstruction === false, "Phase310 construction must not use target observables.");
  assert(phase310.targetValuesUsedOnlyForPostCandidateEvaluation === true, "Phase310 may only inherit targets for post-candidate evaluation.");
  assert(phase310.branchLocalVariationalWorkbenchPresent === true, "Phase310 must confirm the completion revision contains the branch-local variational workbench.");
  assert(phase310.completionDraftProvidesVectorLengthNormalizationTheorem === false, "Phase310 cannot claim the completion draft provides a source-mode-vector-length theorem.");
  assert(phase310.completionDraftProvidesCasimirApplicationTheorem === false, "Phase310 cannot claim the completion draft provides a W-only Casimir application theorem.");
  assert(phase310.completionDraftProvidesChargedLadderTransferTheorem === false, "Phase310 cannot claim the completion draft provides a charged-ladder transfer theorem.");
  assert(phase310.completionDraftProvidesPhysicalWzSourceRowDerivation === false, "Phase310 cannot claim the completion draft derives physical W/Z source rows.");
  assert(phase310.completionDraftProvidesBranchStableSourceRows === false, "Phase310 cannot claim branch-stable physical source rows.");
  assert(phase310.completionDraftCanPromotePhase302Lead === false, "Phase310 cannot promote the Phase302 vector-length/Casimir lead.");
  assert(phase310.canFillPhase201WzContract === false, "Phase310 cannot fill the Phase201 W/Z contract.");
  assert(phase310.wzMissingFieldCount === missingWzFields, "Phase310 W/Z missing-field count must match Phase213.");
  assert(phase310.higgsMissingFieldCount === missingHiggsFields, "Phase310 Higgs missing-field count must match Phase213.");
  assert(phase311.completionObservedSectorWzRowSelectorAuditPassed === true, "Phase311 completion observed-sector W/Z row-selector audit must pass as a non-promotional audit.");
  assert(phase311.targetObservablesUsedForConstruction === false, "Phase311 construction must not use target observables.");
  assert(phase311.targetValuesUsedOnlyForPostCandidateEvaluation === true, "Phase311 may only inherit targets for post-candidate evaluation.");
  assert(phase311.completionDraftObservedSectorProgramPresent === true, "Phase311 must confirm the completion revision has observed-sector recovery governance.");
  assert(phase311.completionDraftTreatsObservedSectorAsPhenomenologicalMapping === true, "Phase311 must keep observed-sector mappings below theorem status.");
  assert(phase311.completionDraftRequiresTypedObservableMapBeforeComparison === true, "Phase311 must preserve the typed observable-map requirement.");
  assert(phase311.completionDraftProvidesCanonicalWzRowSelector === false, "Phase311 cannot claim a canonical physical W/Z row selector.");
  assert(phase311.completionDraftProvidesPhotonWzEigenstateProjectionRows === false, "Phase311 cannot claim photon/W/Z eigenstate projection rows.");
  assert(phase311.completionDraftProvidesPhysicalWzObservableMap === false, "Phase311 cannot claim a physical W/Z observable map.");
  assert(phase311.completionDraftProvidesBranchStableObservedWzRows === false, "Phase311 cannot claim branch-stable observed W/Z rows.");
  assert(phase311.completionDraftCanPromotePhase307Selector === false, "Phase311 cannot promote the Phase307 selector.");
  assert(phase311.phase307RowsHaveObservedSectorMapId === false, "Phase311 must show Phase307 rows lack an observed-sector map id.");
  assert(phase311.phase307RowsHaveElectroweakGaugeEmbeddingId === false, "Phase311 must show Phase307 rows lack an electroweak gauge embedding id.");
  assert(phase311.phase307RowsHaveQuadraticElectroweakMassOperatorId === false, "Phase311 must show Phase307 rows lack a quadratic electroweak mass-operator id.");
  assert(phase311.phase307RowsHavePhotonMasslessGate === false, "Phase311 must show Phase307 rows lack a photon massless gate.");
  assert(phase311.phase307WRowsHavePhysicalEigenstateProjectionId === false, "Phase311 must show Phase307 W rows lack a physical eigenstate projection id.");
  assert(phase311.phase307ZRowsHavePhysicalEigenstateProjectionId === false, "Phase311 must show Phase307 Z rows lack a physical eigenstate projection id.");
  assert(phase311.phase307ObservedProjectionBranchStable === false, "Phase311 must show Phase307 observed projection is not branch-stable.");
  assert(phase311.phase307ObservedProjectionTargetBlindHashPresent === false, "Phase311 must show Phase307 observed projection has no target-blind hash.");
  assert(phase311.phase295PhotonEigenstateProjectionIntakeReady === false, "Phase311 must preserve the missing photon eigenstate projection intake field.");
  assert(phase311.phase295WSourceRowIntakeReady === false, "Phase311 must preserve the missing W source-row intake field.");
  assert(phase311.phase295ZSourceRowIntakeReady === false, "Phase311 must preserve the missing Z source-row intake field.");
  assert(phase311.phase307SelectorStillNonPromotable === true, "Phase311 must preserve Phase307 selector nonpromotability.");
  assert(phase311.canFillPhase201WzContract === false, "Phase311 cannot fill the Phase201 W/Z contract.");
  assert(phase311.wzMissingFieldCount === missingWzFields, "Phase311 W/Z missing-field count must match Phase213.");
  assert(phase311.higgsMissingFieldCount === missingHiggsFields, "Phase311 Higgs missing-field count must match Phase213.");
}

for (const [label, validation, templatePath] of [
  ["W/Z", phase201.wzValidation, phase201.wzTemplatePath],
  ["Higgs", phase201.higgsValidation, phase201.higgsTemplatePath],
]) {
  const template = templatePath ? readOptional(templatePath) : null;
  if (!template) {
    failures.push(`Phase201 ${label} template path is missing or unreadable: ${templatePath ?? "<unset>"}`);
    continue;
  }

  const nullCount = countNulls(template);
  if (nullCount > 0 || template.status === "template-unfilled") {
    assert(validation?.promotable === false, `Phase201 ${label} null placeholders or unfilled template status cannot be treated as promotable evidence.`);
  }

  if (validation?.promotable === true) {
    assert(nullCount === 0, `Phase201 ${label} promotable validation cannot contain null placeholders.`);
    assert(template.status !== "template-unfilled", `Phase201 ${label} promotable validation cannot use template-unfilled status.`);
  }
}

if (failures.length > 0) {
  console.error("boson-claim-integrity-failed");
  for (const failure of failures) {
    console.error(`- ${failure}`);
  }
  process.exit(1);
}

console.log("boson-claim-integrity-verified");
console.log(`sourceLineageMissing=${sourceLineageMissing}`);
console.log(`wzMissingFieldCount=${missingWzFields}`);
console.log(`higgsMissingFieldCount=${missingHiggsFields}`);
console.log(`promotedPhysicalMassClaimCount=${prohibitedPromotedIds.length}`);
